import type { Accessor } from 'solid-js';

/**
 * Resolves a condition (which can be a boolean or a SolidJS accessor returning a boolean) to a concrete boolean value.
 * @param condition - The condition to resolve. Defaults to true if undefined.
 * @returns The resolved boolean value.
 */
/**
 * buildBoolean variable - Auto-generated expression
 * 
 * ⚠️ WARNING: This expression is auto-generated and should not be modified.
 * Any manual changes will be overwritten during the next generation.
 * 
 * @generated
 * @readonly
 * @author chlbri (bri_lvi@icloud.com)
 */
export const buildBoolean = (
  condition?: Accessor<boolean | undefined> | boolean,
) => {
  const _condition =
    typeof condition === 'function'
      ? (condition() ?? true)
      : (condition ?? true);
  return _condition;
};

ui/helpers/circularDirection.text:
/**
 * circularDirection variable - Auto-generated expression
 * 
 * ⚠️ WARNING: This expression is auto-generated and should not be modified.
 * Any manual changes will be overwritten during the next generation.
 * 
 * @generated
 * @readonly
 * @author chlbri (bri_lvi@icloud.com)
 */
export const circularDirection = (
  current: number,
  previous: number,
  last: number,
) => {
  if (current === 0 && previous === last) return 1; // slide droite
  if (current === last && previous === 0) return -1; // slide gauche
  return current > previous ? 1 : -1;
};

