  count: number;
  duration?: number;
  innerProps?: OmitPropsOf<'span', 'children' | 'style'> & {
    style?: JSX.CSSProperties;
  };
}> = ({ count: length, innerProps = {}, duration = 500 }) => {
  const [local, rest] = splitProps(innerProps, ['class', 'style']);

  return (
